    public void handleTrades(Client client, Object message)
    {
        //
        //     {
        //         "channel": "trades",
        //         "data": [
        //             {
        //                 "coin": "BTC",
        //                 "side": "A",
        //                 "px": "68517.0",
        //                 "sz": "0.005",
        //                 "time": 1710125266669,
        //                 "hash": "0xc872699f116e012186620407fc08a802015e0097c5cce74710697f7272e6e959",
        //                 "tid": 981894269203506
        //             }
        //         ]
        //     }
        //
        Object entry = this.safeList(message, "data", new java.util.ArrayList<Object>(java.util.Arrays.asList()));
        Object entryLength = Helpers.getArrayLength(entry);
        if (Helpers.isTrue(Helpers.isEqual(entryLength, 0)))
        {
            return;
        }
        Object first = this.safeDict(entry, 0, new java.util.HashMap<String, Object>() {{}});
        Object coin = this.safeString(first, "coin");
        Object marketId = this.coinToMarketId(coin);
        Object market = this.market(((String)marketId));
        Object symbol = Helpers.GetValue(market, "symbol");
        if (!Helpers.isTrue((Helpers.inOp(this.trades, symbol))))
        {
            Object limit = this.safeInteger(this.options, "tradesLimit", 1000);
            var stored = new ArrayCache(((Number)limit).intValue());
            Helpers.addElementToObject(this.trades, symbol, stored);
        }
        Object trades = Helpers.GetValue(this.trades, symbol);
        for (var i = 0; Helpers.isLessThan(i, Helpers.getArrayLength(entry)); i++)
        {
            Object data = this.safeDict(entry, i, new java.util.HashMap<String, Object>() {{}});
            Object trade = this.parseWsTrade(data);
            Helpers.callDynamically(trades, "append", new Object[]{trade});
        }
        Object messageHash = Helpers.add("trade:", symbol);
        client.resolve(trades, messageHash);
    }

    public Object parseWsTrade(Object trade, Object... optionalArgs)
    {
        //
        // fetchMyTrades
        //
        //     {
        //         "coin": "BTC",
        //         "px": "72528.0",
        //         "sz": "0.11693",
        //         "side": "A",
        //         "time": 1710208712815,
        //         "startPosition": "0.11693",
        //         "dir": "Close Long",
        //         "closedPnl": "-0.81851",
        //         "hash": "0xc5adaf35f8402750c218040b0a7bc301130051521273b6f398b3caad3e1f3f5f",
        //         "oid": 7484888874,
        //         "crossed": true,
        //         "fee": "2.968244",
        //         "liquidationMarkPx": null,
        //         "tid": 567547935839686,
        //         "cloid": null
        //     }
        //
        // fetchTrades
        //
        //     {
        //         "coin": "BTC",
        //         "side": "A",
        //         "px": "68517.0",
        //         "sz": "0.005",
        //         "time": 1710125266669,
        //         "hash": "0xc872699f116e012186620407fc08a802015e0097c5cce74710697f7272e6e959",
        //         "tid": 981894269203506
        //     }
        //
        Object market = Helpers.getArg(optionalArgs, 0, null);
        Object timestamp = this.safeInteger(trade, "time");
        Object price = this.safeString(trade, "px");
        Object amount = this.safeString(trade, "sz");
        Object coin = this.safeString(trade, "coin");
        Object marketId = this.coinToMarketId(coin);
        market = this.safeMarket(marketId, null);
        Object symbol = Helpers.GetValue(market, "symbol");
        Object id = this.safeString(trade, "tid");
        Object side = this.safeString(trade, "side");
        if (Helpers.isTrue(!Helpers.isEqual(side, null)))
        {
            side = ((Helpers.isTrue((Helpers.isEqual(side, "A"))))) ? "sell" : "buy";
        }
        Object fee = this.safeString(trade, "fee");
        final Object finalSide = side;
        return this.safeTrade(new java.util.HashMap<String, Object>() {{
            put( "info", trade );
            put( "timestamp", timestamp );
            put( "datetime", HyperliquidCore.this.iso8601(timestamp) );
            put( "symbol", symbol );
            put( "id", id );
            put( "order", HyperliquidCore.this.safeString(trade, "oid") );
            put( "type", null );
            put( "side", finalSide );
            put( "takerOrMaker", null );
            put( "price", price );
            put( "amount", amount );
            put( "cost", null );
            put( "fee", new java.util.HashMap<String, Object>() {{
                put( "cost", fee );
                put( "currency", "USDC" );
            }} );
        }}, market);
    }

