    public void handleBalance(Client client, Object message)
    {
        //
        // spot
        // {
        //     "channel": "spotState",
        //     "data": {
        //         "user": "0xeeeeexxxxeeeee",
        //         "spotState": {
        //             "balances": [
        //                 {
        //                     "coin": "USDH",
        //                     "token": 360,
        //                     "total": "0.0",
        //                     "hold": "0.0",
        //                     "entryNtl": "0.0"
        //                 }
        //             ],
        //             "tokenToAvailableAfterMaintenance": [
        //                 [
        //                     0,
        //                     "56.1"
        //                 ]
        //             ]
        //         }
        //     }
        // }
        // swap
        // {
        //     "channel": "clearinghouseState",
        //     "data": {
        //         "dex": "",
        //         "user": "0xeeeeexxxxeeeee",
        //         "clearinghouseState": {
        //             "marginSummary": {
        //                 "accountValue": "0.0",
        //                 "totalNtlPos": "0.0",
        //                 "totalRawUsd": "0.0",
        //                 "totalMarginUsed": "0.0"
        //             },
        //             "crossMarginSummary": {
        //                 "accountValue": "0.0",
        //                 "totalNtlPos": "0.0",
        //                 "totalRawUsd": "0.0",
        //                 "totalMarginUsed": "0.0"
        //             },
        //             "crossMaintenanceMarginUsed": "0.0",
        //             "withdrawable": "0.0",
        //             "assetPositions": [],
        //             "time": 1776000003409
        //         }
        //     }
        // }
        //
        if (Helpers.isTrue(Helpers.isEqual(this.balance, null)))
        {
            this.balance = new java.util.HashMap<String, Object>() {{}};
        }
        Object topic = this.safeValue(message, "channel");
        Object messageHash = Helpers.add(topic, "::balance");
        Object info = null;
        Object rawBalances = new java.util.ArrayList<Object>(java.util.Arrays.asList());
        Object account = null;
        Object timestamp = null;
        Object data = this.safeValue(message, "data", new java.util.ArrayList<Object>(java.util.Arrays.asList()));
        if (Helpers.isTrue(Helpers.isEqual(topic, "spotState")))
        {
            Object spotState = this.safeDict(data, "spotState");
            rawBalances = this.safeList(spotState, "balances", new java.util.ArrayList<Object>(java.util.Arrays.asList()));
            account = "spot";
            info = rawBalances;
        }
        if (Helpers.isTrue(Helpers.isEqual(topic, "clearinghouseState")))
        {
            account = "swap";
            Object clearinghouseState = this.safeDict(data, "clearinghouseState");
            ((java.util.List<Object>)rawBalances).add(clearinghouseState);
            info = clearinghouseState;
            timestamp = this.safeInteger(clearinghouseState, "time");
            this.handlePositions(client, message);
        }
        for (var i = 0; Helpers.isLessThan(i, Helpers.getArrayLength(rawBalances)); i++)
        {
            this.parseWsBalance(Helpers.GetValue(rawBalances, i), account);
        }
        if (Helpers.isTrue(Helpers.isEqual(this.safeValue(this.balance, ((String)account)), null)))
        {
            Helpers.addElementToObject(this.balance, ((String)account), new java.util.HashMap<String, Object>() {{}});
        }
        Helpers.addElementToObject(Helpers.GetValue(this.balance, ((String)account)), "info", info);
        Helpers.addElementToObject(Helpers.GetValue(this.balance, ((String)account)), "timestamp", timestamp);
        Helpers.addElementToObject(Helpers.GetValue(this.balance, ((String)account)), "datetime", this.iso8601(timestamp));
        Helpers.addElementToObject(this.balance, ((String)account), this.safeBalance(Helpers.GetValue(this.balance, ((String)account))));
        client.resolve(Helpers.GetValue(this.balance, ((String)account)), messageHash);
    }

    public void parseWsBalance(Object balance, Object... optionalArgs)
    {
        //
        // spot
        //     {
        //         "coin": "USDH",
        //         "token": 360,
        //         "total": "0.0",
        //         "hold": "0.0",
        //         "entryNtl": "0.0"
        //     }
        // swap
        //     {
        //         "marginSummary": {
        //             "accountValue": "0.0",
        //             "totalNtlPos": "0.0",
        //             "totalRawUsd": "0.0",
        //             "totalMarginUsed": "0.0"
        //         },
        //         "crossMarginSummary": {
        //             "accountValue": "0.0",
        //             "totalNtlPos": "0.0",
        //             "totalRawUsd": "0.0",
        //             "totalMarginUsed": "0.0"
        //         },
        //         "crossMaintenanceMarginUsed": "0.0",
        //         "withdrawable": "0.0",
        //         "assetPositions": [],
        //         "time": 1776000003409
        //     }
        //
        Object accountType = Helpers.getArg(optionalArgs, 0, null);
        Object account = this.account();
        Object currencyId = this.safeString(balance, "coin");
        Object code = null;
        if (Helpers.isTrue(Helpers.isEqual(currencyId, null)))
        {
            code = "USDC";
            Object marginSummary = this.safeDict(balance, "marginSummary", new java.util.HashMap<String, Object>() {{}});
            Helpers.addElementToObject(account, "free", this.safeString(balance, "withdrawable"));
            Helpers.addElementToObject(account, "used", this.safeString(marginSummary, "totalMarginUsed"));
            Helpers.addElementToObject(account, "total", this.safeString(marginSummary, "accountValue"));
        } else
        {
            code = this.safeCurrencyCode(currencyId);
            Helpers.addElementToObject(account, "used", this.safeString(balance, "hold"));
            Helpers.addElementToObject(account, "total", this.safeString(balance, "total"));
        }
        if (Helpers.isTrue(!Helpers.isEqual(accountType, null)))
        {
            if (Helpers.isTrue(Helpers.isEqual(this.safeValue(this.balance, accountType), null)))
            {
                Helpers.addElementToObject(this.balance, accountType, new java.util.HashMap<String, Object>() {{}});
            }
            Helpers.addElementToObject(Helpers.GetValue(this.balance, accountType), code, account);
        } else
        {
            Helpers.addElementToObject(this.balance, code, account);
        }
    }

    /**
     * @method
     * @name hyperliquid#watchPositions
     * @see https://hyperliquid.gitbook.io/hyperliquid-docs/for-developers/api/websocket/subscriptions
     * @description watch all open positions
     * @param {string[]} [symbols] list of unified market symbols
     * @param {int} [since] the earliest time in ms to fetch positions for
     * @param {int} [limit] the maximum number of positions to retrieve
     * @param {object} params extra parameters specific to the exchange API endpoint
     * @param {string} [params.dex] for hip3 tokens subscription, eg: 'xyz' or 'flx`, if symbols are provided we will infer it from the first symbol's market
     * @returns {object[]} a list of [position structure]{@link https://docs.ccxt.com/en/latest/manual.html#position-structure}
     */
    public java.util.concurrent.CompletableFuture<Object> watchPositions(Object... optionalArgs)
    {

        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {

            Object symbols = Helpers.getArg(optionalArgs, 0, null);
            Object since = Helpers.getArg(optionalArgs, 1, null);
            Object limit = Helpers.getArg(optionalArgs, 2, null);
            Object parameters = Helpers.getArg(optionalArgs, 3, new java.util.HashMap<String, Object>() {{}});
            (this.loadMarkets()).join();
            Object userAddress = null;
            Object userAddressResult = this.handlePublicAddress("watchPositions", parameters);
            userAddress = this.safeString(userAddressResult, 0);
            parameters = this.safeDict(userAddressResult, 1, parameters);
            Object topic = "clearinghouseState";
            Object messageHash = Helpers.add(topic, "::positions");
            if (Helpers.isTrue(Helpers.isTrue((!Helpers.isEqual(symbols, null))) && !Helpers.isTrue(this.isEmpty(symbols))))
            {
                symbols = this.marketSymbols(symbols);
                messageHash = Helpers.add(messageHash, Helpers.add("::", String.join((String)",", (java.util.List<String>)symbols)));
            }
            Object url = Helpers.GetValue(Helpers.GetValue(Helpers.GetValue(this.urls, "api"), "ws"), "public");
            final Object finalTopic = topic;
            final Object finalUserAddress = userAddress;
            Object subscription = new java.util.HashMap<String, Object>() {{
                put( "type", finalTopic );
                put( "user", finalUserAddress );
            }};
            Object dexName = this.getDexFromSymbols("watchPositions", symbols);
            if (Helpers.isTrue(!Helpers.isEqual(dexName, null)))
            {
                Helpers.addElementToObject(subscription, "dex", dexName);
            }
            Object request = new java.util.HashMap<String, Object>() {{
                put( "method", "subscribe" );
                put( "subscription", subscription );
            }};
            Object message = this.extend(request, parameters);
            Client client = this.client(url);
            this.setPositionsCache(client, symbols);
            Object cache = this.positions;
            Object newPositions = (this.watch(url, messageHash, message, topic, null)).join();
            if (Helpers.isTrue(this.newUpdates))
            {
                return newPositions;
            }
            return this.filterBySymbolsSinceLimit(cache, symbols, since, limit, true);
        });

    }

    public void setPositionsCache(Client client, Object... optionalArgs)
    {
        Object symbols = Helpers.getArg(optionalArgs, 0, null);
        if (Helpers.isTrue(!Helpers.isEqual(this.positions, null)))
        {
            return;
        }
        this.positions = new ArrayCache.ArrayCacheBySymbolBySide();
    }

    public void handlePositions(Client client, Object message)
    {
        if (Helpers.isTrue(Helpers.isEqual(this.positions, null)))
        {
            this.positions = new ArrayCache.ArrayCacheBySymbolBySide();
        }
        Object cache = this.positions;
        Object data = this.safeDict(message, "data", new java.util.HashMap<String, Object>() {{}});
        Object clearinghouseState = this.safeDict(data, "clearinghouseState", new java.util.HashMap<String, Object>() {{}});
        Object newPositions = new java.util.ArrayList<Object>(java.util.Arrays.asList());
        Object rawPositions = this.safeList(clearinghouseState, "assetPositions", new java.util.ArrayList<Object>(java.util.Arrays.asList()));
        for (var i = 0; Helpers.isLessThan(i, Helpers.getArrayLength(rawPositions)); i++)
        {
            Object rawPosition = Helpers.GetValue(rawPositions, i);
            Object position = this.parsePosition(rawPosition);
            ((java.util.List<Object>)newPositions).add(position);
            Helpers.callDynamically(cache, "append", new Object[]{position});
        }
        Object baseMessageHash = "clearinghouseState::positions";
        Object messageHashes = this.findMessageHashes(client, baseMessageHash);
        for (var i = 0; Helpers.isLessThan(i, Helpers.getArrayLength(messageHashes)); i++)
        {
            Object messageHash = Helpers.GetValue(messageHashes, i);
            Object parts = Helpers.split(messageHash, "::");
            Object symbolsString = this.safeString(parts, 2);
            if (Helpers.isTrue(Helpers.isEqual(symbolsString, null)))
            {
                continue;
            }
            Object symbols = Helpers.split(symbolsString, ",");
            Object positions = this.filterByArray(newPositions, "symbol", symbols, false);
            if (!Helpers.isTrue(this.isEmpty(positions)))
            {
                client.resolve(positions, messageHash);
            }
        }
        client.resolve(newPositions, baseMessageHash);
    }

